// ---------------------------------------------------------------------------
// Imports
// ---------------------------------------------------------------------------

import 'dart:typed_data';

import 'camo_key_cache.dart';
import 'key_cache_entry.dart';

// ---------------------------------------------------------------------------
// Memory Key Cache
// ---------------------------------------------------------------------------

class CamoMemoryKeyCache implements CamoKeyCache {
  // ---------------------------------------------------------------------------
  // Properties
  // ---------------------------------------------------------------------------

  final Map<String, KeyCacheEntry> _cache = <String, KeyCacheEntry>{};

  // ---------------------------------------------------------------------------
  // Get
  // ---------------------------------------------------------------------------

  @override
  KeyCacheEntry? get(
    String pairId,
  ) {
    return _cache[pairId];
  }

  // ---------------------------------------------------------------------------
  // Put
  // ---------------------------------------------------------------------------

  @override
  void put({
    required String pairId,
    required Uint8List key,
  }) {
    _cache[pairId] = KeyCacheEntry(
      key: Uint8List.fromList(key),
      createdAt: DateTime.now().toUtc(),
    );
  }

  // ---------------------------------------------------------------------------
  // Remove
  // ---------------------------------------------------------------------------

  @override
  void remove(
    String pairId,
  ) {
    _cache.remove(pairId);
  }

  // ---------------------------------------------------------------------------
  // Clear
  // ---------------------------------------------------------------------------

  @override
  void clear() {
    _cache.clear();
  }
}